pre_operations {
  -- Pre-operation: Log the start of the daily incremental load
  CREATE TABLE IF NOT EXISTS ${self()}_audit_log (
    run_time TIMESTAMP,
    status STRING
  );

  INSERT INTO ${self()}_audit_log (run_time, status) 
  VALUES (CURRENT_TIMESTAMP(), 'STARTED');
}

SELECT
  CAST(claim_id AS INT64) AS claim_id,
  CAST(model AS STRING) AS model,
  CAST(dealer AS STRING) AS dealer,
  CAST(mileage AS INT64) AS mileage,
  CAST(repair_cost AS NUMERIC) AS repair_cost,
  CAST(failure_code AS STRING) AS failure_code,
  CAST(claim_date AS DATE) AS claim_date
FROM
  ${ref("warranty_claims_raw")}
-- Incrementally process only new records based on the latest claim_date available
${when(incremental(), `WHERE CAST(claim_date AS DATE) > (SELECT COALESCE(MAX(claim_date), '1900-01-01') FROM ${self()})`)}

post_operations {
  -- Post-operation: Data validation check to catch negative repair costs or NULL mileages
  CREATE TABLE IF NOT EXISTS ${self()}_dq_alerts (
    claim_id INT64,
    issue STRING,
    alert_time TIMESTAMP
  );

  INSERT INTO ${self()}_dq_alerts (claim_id, issue, alert_time)
  SELECT 
    claim_id, 
    'Data Quality Alert: Negative repair_cost or missing mileage detected' AS issue,
    CURRENT_TIMESTAMP() AS alert_time
  FROM ${self()}
  WHERE repair_cost < 0 OR mileage IS NULL;

  -- Log successful completion of the pipeline
  INSERT INTO ${self()}_audit_log (run_time, status) 
  VALUES (CURRENT_TIMESTAMP(), 'COMPLETED');
}

