  const [claims] = useState(mockClaims);
  const [sortConfig, setSortConfig] = useState({ key: 'date', direction: 'desc' });
  const [filterText, setFilterText] = useState('');
  const [filterStatus, setFilterStatus] = useState('All');

  // Handle column header clicks for sorting
  const handleSort = (key) => {
    let direction = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  // Filter and sort the claims data using useMemo to optimize performance
  const processedClaims = useMemo(() => {
    // 1. Filter
    let filtered = claims.filter((claim) => {
      const matchesText = claim.customer.toLowerCase().includes(filterText.toLowerCase()) || 
                          claim.id.toLowerCase().includes(filterText.toLowerCase());
      const matchesStatus = filterStatus === 'All' || claim.status === filterStatus;

      return matchesText && matchesStatus;
    });

    // 2. Sort
    filtered.sort((a, b) => {
      if (a[sortConfig.key] < b[sortConfig.key]) {
        return sortConfig.direction === 'asc' ? -1 : 1;
      }
      if (a[sortConfig.key] > b[sortConfig.key]) {
        return sortConfig.direction === 'asc' ? 1 : -1;
      }
      return 0;
    });

    return filtered;
  }, [claims, sortConfig, filterText, filterStatus]);

  // Render sorting indicator arrow
  const getSortIcon = (columnName) => {
    if (sortConfig.key === columnName) {
      return sortConfig.direction === 'asc' ? ' ▲' : ' ▼';
