          placeholder="Search by Claim ID or Customer..." 
          value={filterText}
          onChange={(e) => setFilterText(e.target.value)}
          style={{ padding: '8px', width: '250px', borderRadius: '4px', border: '1px solid #ccc' }}
        />

        <select 
          value={filterStatus} 
          onChange={(e) => setFilterStatus(e.target.value)}
