        <thead>
          <tr style={{ backgroundColor: '#f4f4f4', textAlign: 'left' }}>
            <th onClick={() => handleSort('id')} style={thStyle}>Claim ID{getSortIcon('id')}</th>
            <th onClick={() => handleSort('customer')} style={thStyle}>Customer{getSortIcon('customer')}</th>
            <th onClick={() => handleSort('date')} style={thStyle}>Date{getSortIcon('date')}</th>
            <th onClick={() => handleSort('amount')} style={thStyle}>Amount{getSortIcon('amount')}</th>
            <th onClick={() => handleSort('status')} style={thStyle}>Status{getSortIcon('status')}</th>
          </tr>
        </thead>
        <tbody>
          {processedClaims.map(claim => (
            <tr key={claim.id} style={{ borderBottom: '1px solid #eee' }}>
              <td style={tdStyle}>{claim.id}</td>
              <td style={tdStyle}>{claim.customer}</td>
              <td style={tdStyle}>{claim.date}</td>
              <td style={tdStyle}>${claim.amount.toFixed(2)}</td>
              <td style={tdStyle}>
                <span style={{
                  padding: '4px 8px',
                  borderRadius: '12px',
                  fontSize: '0.85em',
                  backgroundColor: claim.status === 'Approved' ? '#d4edda' : 
                                   claim.status === 'Rejected' ? '#f8d7da' : '#fff3cd',
                  color: claim.status === 'Approved' ? '#155724' : 
                         claim.status === 'Rejected' ? '#721c24' : '#856404'
                }}>
                  {claim.status}
                </span>
              </td>
            </tr>
          ))}
          {processedClaims.length === 0 && (
            <tr>
              <td colSpan="5" style={{ padding: '20px', textAlign: 'center', color: '#666' }}>
                No warranty claims found matching your criteria.
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
};

