    def test_add_floats(self):
        # assertAlmostEqual is used to handle floating-point precision issues
        self.assertAlmostEqual(add(10.5, 5.2), 15.7)
        self.assertAlmostEqual(add(-10.5, 5.5), -5.0)

    def test_add_strings(self):
        self.assertEqual(add("hello", " world"), "hello world")
        self.assertEqual(add("", "test"), "test")
        self.assertEqual(add("", ""), "")

